"""
內嵌圖示資料模組
自動生成於圖片: moni.ico
"""

import base64
from PyQt6.QtGui import QIcon, QPixmap

# Base64 編碼的圖示資料
MONI_ICON_DATA = """

"""

def get_moni_icon():
    """返回 moni 圖示"""
    pixmap = QPixmap()
    pixmap.loadFromData(base64.b64decode(MONI_ICON_DATA))
    return QIcon(pixmap)

def get_moni_pixmap():
    """返回 moni 像素圖"""
    pixmap = QPixmap()
    pixmap.loadFromData(base64.b64decode(MONI_ICON_DATA))
    return pixmap

